import asyncio
import json
import logging
import secrets
from collections import defaultdict
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Tuple

import websockets
from websockets.server import WebSocketServerProtocol


logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s")


@dataclass
class Item:
    id: str
    name: str
    owner_id: str


@dataclass
class Player:
    id: str
    name: str
    websocket: Optional[WebSocketServerProtocol] = None
    inventory: Set[str] = field(default_factory=set)


class MMOGameServer:
    def __init__(self, host: str = "0.0.0.0", port: int = 8765):
        self.host = host
        self.port = port

        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self.player_locks: Dict[str, asyncio.Lock] = defaultdict(asyncio.Lock)
        self.global_lock = asyncio.Lock()
        self.connections: Dict[WebSocketServerProtocol, str] = {}

    async def send(self, websocket: WebSocketServerProtocol, message: dict):
        try:
            await websocket.send(json.dumps(message))
        except Exception as e:
            logging.warning("Send failed: %s", e)

    async def broadcast_to_players(self, player_ids: Set[str], message: dict):
        tasks = []
        for player_id in player_ids:
            player = self.players.get(player_id)
            if player and player.websocket:
                tasks.append(self.send(player.websocket, message))
        if tasks:
            await asyncio.gather(*tasks, return_exceptions=True)

    async def register_player(self, websocket: WebSocketServerProtocol, data: dict):
        player_id = data.get("player_id")
        name = data.get("name", f"Player-{player_id}")

        if not player_id:
            await self.send(websocket, {"type": "error", "message": "player_id required"})
            return

        async with self.global_lock:
            player = self.players.get(player_id)
            if player is None:
                player = Player(id=player_id, name=name, websocket=websocket)
                self.players[player_id] = player
                for i in range(3):
                    item_id = secrets.token_hex(8)
                    item = Item(id=item_id, name=f"StarterItem{i+1}", owner_id=player_id)
                    self.items[item_id] = item
                    player.inventory.add(item_id)
            else:
                player.websocket = websocket
                if name:
                    player.name = name

            self.connections[websocket] = player_id

        await self.send(
            websocket,
            {
                "type": "registered",
                "player_id": player.id,
                "name": player.name,
                "inventory": [self.serialize_item(self.items[item_id]) for item_id in player.inventory],
            },
        )

    async def unregister(self, websocket: WebSocketServerProtocol):
        player_id = self.connections.pop(websocket, None)
        if not player_id:
            return
        player = self.players.get(player_id)
        if player and player.websocket == websocket:
            player.websocket = None
        logging.info("Disconnected player %s", player_id)

    def serialize_item(self, item: Item) -> dict:
        return {"id": item.id, "name": item.name, "owner_id": item.owner_id}

    async def get_inventory(self, websocket: WebSocketServerProtocol):
        player_id = self.connections.get(websocket)
        if not player_id:
            await self.send(websocket, {"type": "error", "message": "not registered"})
            return

        player = self.players.get(player_id)
        if not player:
            await self.send(websocket, {"type": "error", "message": "player not found"})
            return

        await self.send(
            websocket,
            {
                "type": "inventory",
                "player_id": player_id,
                "inventory": [self.serialize_item(self.items[item_id]) for item_id in player.inventory if item_id in self.items],
            },
        )

    async def transfer_item(self, websocket: WebSocketServerProtocol, data: dict):
        from_player_id = self.connections.get(websocket)
        to_player_id = data.get("to_player_id")
        item_id = data.get("item_id")

        if not from_player_id:
            await self.send(websocket, {"type": "error", "message": "not registered"})
            return
        if not to_player_id or not item_id:
            await self.send(websocket, {"type": "error", "message": "to_player_id and item_id required"})
            return
        if from_player_id == to_player_id:
            await self.send(websocket, {"type": "error", "message": "cannot transfer to self"})
            return

        async with self.global_lock:
            if from_player_id not in self.players or to_player_id not in self.players:
                await self.send(websocket, {"type": "error", "message": "invalid player"})
                return

        first_id, second_id = sorted([from_player_id, to_player_id])

        async with self.player_locks[first_id]:
            async with self.player_locks[second_id]:
                from_player = self.players.get(from_player_id)
                to_player = self.players.get(to_player_id)
                item = self.items.get(item_id)

                if not from_player or not to_player or not item:
                    await self.send(websocket, {"type": "error", "message": "invalid transfer state"})
                    return

                if item.owner_id != from_player_id or item_id not in from_player.inventory:
                    await self.send(
                        websocket,
                        {
                            "type": "transfer_result",
                            "success": False,
                            "message": "item not owned by sender",
                            "item_id": item_id,
                        },
                    )
                    return

                from_player.inventory.remove(item_id)
                to_player.inventory.add(item_id)
                item.owner_id = to_player_id

                message = {
                    "type": "transfer_result",
                    "success": True,
                    "from_player_id": from_player_id,
                    "to_player_id": to_player_id,
                    "item": self.serialize_item(item),
                }

                await self.broadcast_to_players({from_player_id, to_player_id}, message)

    async def update_item_ownership(self, websocket: WebSocketServerProtocol, data: dict):
        requester_id = self.connections.get(websocket)
        item_id = data.get("item_id")
        new_owner_id = data.get("new_owner_id")

        if not requester_id:
            await self.send(websocket, {"type": "error", "message": "not registered"})
            return
        if not item_id or not new_owner_id:
            await self.send(websocket, {"type": "error", "message": "item_id and new_owner_id required"})
            return

        async with self.global_lock:
            item = self.items.get(item_id)
            new_owner = self.players.get(new_owner_id)
            if not item or not new_owner:
                await self.send(websocket, {"type": "error", "message": "invalid item or owner"})
                return
            old_owner_id = item.owner_id
            if old_owner_id not in self.players:
                await self.send(websocket, {"type": "error", "message": "current owner missing"})
                return

        if requester_id != old_owner_id:
            await self.send(
                websocket,
                {
                    "type": "ownership_update",
                    "success": False,
                    "message": "requester does not own item",
                    "item_id": item_id,
                },
            )
            return

        if old_owner_id == new_owner_id:
            await self.send(
                websocket,
                {
                    "type": "ownership_update",
                    "success": True,
                    "message": "owner unchanged",
                    "item": self.serialize_item(item),
                },
            )
            return

        first_id, second_id = sorted([old_owner_id, new_owner_id])

        async with self.player_locks[first_id]:
            async with self.player_locks[second_id]:
                item = self.items.get(item_id)
                old_owner = self.players.get(old_owner_id)
                new_owner = self.players.get(new_owner_id)

                if not item or not old_owner or not new_owner:
                    await self.send(websocket, {"type": "error", "message": "state changed"})
                    return

                if item.owner_id != requester_id or item_id not in old_owner.inventory:
                    await self.send(
                        websocket,
                        {
                            "type": "ownership_update",
                            "success": False,
                            "message": "ownership changed concurrently",
                            "item_id": item_id,
                        },
                    )
                    return

                old_owner.inventory.remove(item_id)
                new_owner.inventory.add(item_id)
                item.owner_id = new_owner_id

                message = {
                    "type": "ownership_update",
                    "success": True,
                    "from_player_id": old_owner_id,
                    "to_player_id": new_owner_id,
                    "item": self.serialize_item(item),
                }
                await self.broadcast_to_players({old_owner_id, new_owner_id}, message)

    async def handle_message(self, websocket: WebSocketServerProtocol, raw_message: str):
        try:
            data = json.loads(raw_message)
        except json.JSONDecodeError:
            await self.send(websocket, {"type": "error", "message": "invalid json"})
            return

        action = data.get("action")
        if action == "register":
            await self.register_player(websocket, data)
        elif action == "get_inventory":
            await self.get_inventory(websocket)
        elif action == "transfer_item":
            await self.transfer_item(websocket, data)
        elif action == "update_item_ownership":
            await self.update_item_ownership(websocket, data)
        else:
            await self.send(websocket, {"type": "error", "message": "unknown action"})

    async def client_handler(self, websocket: WebSocketServerProtocol):
        logging.info("Client connected")
        try:
            async for message in websocket:
                await self.handle_message(websocket, message)
        except websockets.ConnectionClosed:
            pass
        finally:
            await self.unregister(websocket)

    async def start(self):
        logging.info("Starting MMO server on %s:%s", self.host, self.port)
        async with websockets.serve(self.client_handler, self.host, self.port, ping_interval=20, ping_timeout=20):
            await asyncio.Future()


